// Combine idea data with analytics insights
const ideaData = $('Get Approved Ideas1').item.json;
const analytics = $input.first().json;

// Format analytics for Gemini prompt
const hookPatterns = analytics.top_hook_patterns || [];
const viralExamples = analytics.viral_examples || [];
const durationInsights = analytics.duration_insights || {};
const keywords = analytics.winning_keywords || [];

// Build analytics summary
let analyticsSummary = '';

if (hookPatterns.length > 0) {
  analyticsSummary += '\n**TOP PERFORMING HOOK PATTERNS IN THIS NICHE:**\n';
  hookPatterns.forEach(h => {
    analyticsSummary += `- ${h.pattern_name}: ${Math.round(h.avg_engagement)}% avg engagement (${h.uses} uses)\n`;
  });
}

if (viralExamples.length > 0) {
  analyticsSummary += '\n**RECENT VIRAL SCRIPTS FROM THIS NICHE:**\n';
  viralExamples.slice(0, 2).forEach((v, i) => {
    if (v.script_text) {
      analyticsSummary += `\nExample ${i+1} (${Math.round(v.views/1000)}K views, ${v.engagement_rate?.toFixed(1)}% engagement):\n`;
      analyticsSummary += v.script_text.substring(0, 200) + '...\n';
    }
  });
}

if (durationInsights.viral_avg_duration) {
  analyticsSummary += `\n**OPTIMAL LENGTH:** Viral videos in this niche average ${durationInsights.viral_avg_duration} seconds.\n`;
}

if (keywords.length > 0) {
  analyticsSummary += `\n**WINNING KEYWORDS:** ${keywords.join(', ')}\n`;
}

return {
  ...ideaData,
  analytics_summary: analyticsSummary,
  target_duration: durationInsights.viral_avg_duration || 35,
  top_hook_pattern: hookPatterns[0]?.pattern_name || ideaData.hook_pattern,
  all_hook_patterns: analytics.all_hook_patterns
};

