const outputItems = [];

for (const item of items) {

  // 1️⃣ Get raw Gemini text
  let raw = item.json?.content?.parts?.[0]?.text ?? '';

  if (!raw) {
    throw new Error('Gemini returned empty response');
  }

  // 2️⃣ Remove markdown code fences
  raw = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // 3️⃣ Parse JSON safely
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (error) {
    throw new Error(`Invalid JSON from Gemini:\n${raw}`);
  }

  // 4️⃣ Return clean structured output
  outputItems.push({
    json: {
      hook: parsed.hook ?? null,
      hook_pattern_id: parsed.hook_pattern_id ?? null
    }
  });
}

return outputItems;
